import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Use a safe maximum buffer size to prevent buffer overflow
        int bufferSize = Math.min(name.length(), 10);

        // Copy only up to bufferSize bytes from user input to the buffer
        byte[] buffer = new byte[10];
        System.arraycopy(name.getBytes(), 0, buffer, 0, bufferSize);

        System.out.println("Hello, " + new String(buffer));
    }
}

